import hero from "../assets/hero.png";

function Hero() {
  return (
    <div className="hero">

      {/* LEFT SIDE TEXT */}
      <div>
        <h1>AI Powered Talent Management</h1>
        <p>Smart recruitment system for modern companies</p>

        <button className="btn">Get Started</button>
      </div>

      {/* RIGHT SIDE IMAGE */}
      <div>
        <img src={hero} className="hero-img" />
      </div>

    </div>
  );
}

export default Hero;
